#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <sys/types.h>
#include <sys/ipc.h>
#include <sys/msg.h>

struct msgbuf {
 long mtype;
 char mtext[100];
};

int main() {
 key_t key = ftok("/tmp", 'A');
 int msgid = msgget(key, IPC_CREAT | 0666);

 struct msgbuf msg;
 msg.mtype = 1;
 strcpy(msg.mtext, "Hello from producer");

 // Producer sends
 msgsnd(msgid, &msg, sizeof(msg.mtext), 0);

 // Consumer receives
 msgrcv(msgid, &msg, sizeof(msg.mtext), 1, 0);
 printf("Received: %s\n", msg.mtext);

 // Remove queue
 msgctl(msgid, IPC_RMID, NULL);
 return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <sys/types.h>
#include <sys/ipc.h>
#include <sys/shm.h>

int main() {
 key_t key = ftok("/tmp", 'B');
 int shmid = shmget(key, 1024, IPC_CREAT | 0666);

 char *shm_ptr = (char*)shmat(shmid, NULL, 0);

 pid_t pid = fork();

 if (pid == 0) {
 // Child writes
 sprintf(shm_ptr, "Data from child");
 } else {
 // Parent reads
 wait(NULL);
 printf("Parent read: %s\n", shm_ptr);
 }

 shmdt(shm_ptr);
 shmctl(shmid, IPC_RMID, NULL);
 return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <sys/types.h>
#include <sys/ipc.h>
#include <sys/sem.h>

union semun {
 int val;
 struct semid_ds *buf;
 unsigned short *array;
};

int main() {
 key_t key = ftok("/tmp", 'C');
 int semid = semget(key, 1, IPC_CREAT | 0666);

 // Initialize semaphore to 1 (binary semaphore)
 union semun arg;
 arg.val = 1;
 semctl(semid, 0, SETVAL, arg);

 struct sembuf sb;
 sb.sem_num = 0;
 sb.sem_op = -1; // Wait (P operation)
 sb.sem_flg = 0;

 // Critical section
 semop(semid, &sb, 1);
 printf("In critical section\n");

 sb.sem_op = 1; // Signal (V operation)
 semop(semid, &sb, 1);

 // Remove semaphore
 semctl(semid, 0, IPC_RMID);
 return 0;
}
